import numpy as np

def sigmoid(x):
    return 1.0 / (1.0 + np.exp(-x))

def sigmoid_derivative(x):
    s = sigmoid(x)
    return s * (1.0 - s)

for x in [-10, -2, 0, 2, 10]:
    print(f"x={x:3d}  sigma={sigmoid(x):.4f}  sigma'={sigmoid_derivative(x):.4f}")

import numpy as np

def sigmoid_stable(x):
    return np.where(
        x >= 0,
        1.0 / (1.0 + np.exp(-x)),
        np.exp(x) / (1.0 + np.exp(x)),
    )

x = np.array([-500.0, -1.0, 0.0, 1.0, 500.0])
print(sigmoid_stable(x))
